以下是一个简单的基于异或运算的key secret加解密算法：

```C++
#include <iostream>
#include <string>

void encrypt(std::string& message, const std::string& key) {
    for (std::size_t i = 0; i < message.length(); ++i) {
        message[i] ^= key[i % key.length()];
    }
}

void decrypt(std::string& message, const std::string& key) {
    encrypt(message, key); // 异或运算具有对称性，解密只需要再次加密
}

int main() {
    std::string message{"Hello, world!"};
    std::string key{"mysecretkey"};

    encrypt(message, key);
    std::cout << "Encrypted message: " << message << '\n';

    decrypt(message, key);
    std::cout << "Decrypted message: " << message << '\n';

    return 0;
}
```

以上代码使用了两个简单的函数来进行加解密操作，encrypt函数将message中每个字符与key中对应位置的字符进行异或计算，decrypt函数则是对encrypt的逆操作。在实际使用中，key应该足够长以确保加密的安全性。

pugi是一个用于解析和构建XML文档的C++库，下面是一个使用pugi库实现读取和保存XML文档的示例代码：

```C++
#include <iostream>
#include "pugixml.hpp"

int main() {
    // 创建一个空的XML文档
    pugi::xml_document doc;

    // 加载XML文档
    if (!doc.load_file("example.xml")) {
        std::cerr << "Failed to load XML file\n";
        return 1;
    }

    // 读取XML文档中的元素和属性
    std::cout << "Root element name: " << doc.child("root").name() << '\n';

    for (pugi::xml_node node : doc.child("root").children()) {
        std::cout << "Element name: " << node.name();
        if (node.attribute("attribute")) {
            std::cout << ", attribute value: " << node.attribute("attribute").value();
        }
        std::cout << '\n';
    }

    // 创建新的XML元素和属性
    pugi::xml_node new_node = doc.child("root").append_child("new_element");
    new_node.append_attribute("new_attribute").set_value("new_value");

    // 保存更新后的XML文档
    if (!doc.save_file("example_updated.xml")) {
        std::cerr << "Failed to save XML file\n";
        return 1;
    }

    std::cout << "XML file successfully updated\n";
    return 0;
}
```

以上代码使用了pugi库中的xml_document类和xml_node类来操作XML文档。load_file函数用于加载XML文档，child函数用于获取子元素，children函数用于获取子元素集合，attribute函数用于获取属性，append_child函数用于添加新的XML元素，set_value函数用于设置属性值，save_file函数用于保存XML文档。

下面是一个简单的基于SHA256哈希算法的key secret哈希加密算法的示例代码：

```C++
#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>
#include "openssl/sha.h"

std::string hash(const std::string& message, const std::string& key) {
    std::stringstream ss;

    // 将key和message相加
    std::string hash_input = key + message;

    // 进行SHA256哈希
    unsigned char digest[SHA256_DIGEST_LENGTH];
    SHA256(reinterpret_cast<const unsigned char*>(hash_input.c_str()), hash_input.length(), digest);

    // 将哈希结果转换为十六进制字符串
    ss << std::hex << std::setfill('0');
    for (int i = 0; i < SHA256_DIGEST_LENGTH; ++i) {
        ss << std::setw(2) << static_cast<int>(digest[i]);
    }

    return ss.str();
}

int main() {
    std::string message{"Hello, world!"};
    std::string key{"mysecretkey"};

    std::string hashed_value = hash(message, key);
    std::cout << "Hashed value: " << hashed_value << '\n';

    return 0;
}
```

以上代码使用了OpenSSL库中的SHA256哈希函数来进行加密操作，将key和message拼接后进行SHA256哈希，再将哈希结果转换为十六进制字符串作为加密后的值。在实际使用中，key应该足够长以确保加密的安全性，同时也可以通过多次迭代哈希来增加加密强度。

以下是一个基于AES加密算法的key secret加解密的示例代码：

```C++
#include <iostream>
#include <string>
#include <cstring>
#include <openssl/evp.h>

std::string encrypt(const std::string& message, const std::string& key) {
    // 创建加密上下文
    EVP_CIPHER_CTX* ctx = EVP_CIPHER_CTX_new();
    if (ctx == nullptr) {
        std::cerr << "Failed to create encryption context\n";
        return "";
    }

    // 初始化加密上下文
    if (EVP_EncryptInit_ex(ctx, EVP_aes_256_cbc(), nullptr, nullptr, nullptr) != 1) {
        std::cerr << "Failed to initialize encryption context\n";
        EVP_CIPHER_CTX_free(ctx);
        return "";
    }

    // 设置加密秘钥和IV
    if (EVP_EncryptInit_ex(ctx, nullptr, nullptr, reinterpret_cast<const unsigned char*>(key.c_str()), nullptr) != 1) {
        std::cerr << "Failed to set encryption key and IV\n";
        EVP_CIPHER_CTX_free(ctx);
        return "";
    }

    // 计算加密后的消息长度
    const int out_len = message.length() + EVP_CIPHER_block_size(EVP_aes_256_cbc());
    unsigned char* out = new unsigned char[out_len];

    // 进行加密操作
    int out_final_len = 0;
    if (EVP_EncryptUpdate(ctx, out, &out_final_len, reinterpret_cast<const unsigned char*>(message.c_str()), message.length()) != 1) {
        std::cerr << "Failed to perform encryption\n";
        delete[] out;
        EVP_CIPHER_CTX_free(ctx);
        return "";
    }

    // 完成加密操作
    if (EVP_EncryptFinal_ex(ctx, out + out_final_len, &out_final_len) != 1) {
        std::cerr << "Failed to finish encryption\n";
        delete[] out;
        EVP_CIPHER_CTX_free(ctx);
        return "";
    }
    out_final_len += out_final_len;

    // 转换加密后的消息为十六进制字符串
    std::string result(reinterpret_cast<char*>(out), out_final_len);
    delete[] out;

    // 释放加密上下文
    EVP_CIPHER_CTX_free(ctx);

    return result;
}

std::string decrypt(const std::string& ciphertext, const std::string& key) {
    // 创建解密上下文
    EVP_CIPHER_CTX* ctx = EVP_CIPHER_CTX_new();
    if (ctx == nullptr) {
        std::cerr << "Failed to create decryption context\n";
        return "";
    }

    // 初始化解密上下文
    if (EVP_DecryptInit_ex(ctx, EVP_aes_256_cbc(), nullptr, nullptr, nullptr) != 1) {
        std::cerr << "Failed to initialize decryption context\n";
        EVP_CIPHER_CTX_free(ctx);
        return "";
    }

    // 设置解密秘钥和IV
    if (EVP_DecryptInit_ex(ctx, nullptr, nullptr, reinterpret_cast<const unsigned char*>(key.c_str()), nullptr) != 1) {
        std::cerr << "Failed to set decryption key and IV\n";
        EVP_CIPHER_CTX_free(ctx);
        return "";
    }

    // 计算解密后的消息长度
    const int out_len = ciphertext.length();
    unsigned char* out = new unsigned char[out_len];

    // 进行解密操作
    int out_final_len = 0;
    if (EVP_DecryptUpdate(ctx, out, &out_final_len, reinterpret_cast<const unsigned char*>(ciphertext.c_str()), ciphertext.length()) != 1) {
        std::cerr << "Failed to perform decryption\n";
        delete[] out;
        EVP_CIPHER_CTX_free(ctx);
        return "";
    }

    // 完成解密操作
    if (EVP_DecryptFinal_ex(ctx, out + out_final_len, &out_final_len) != 1) {
        std::cerr << "Failed to finish decryption\n";
        delete[] out;
        EVP_CIPHER_CTX_free(ctx);
        return "";
    }
    out_final_len += out_final_len;

    // 转换解密后的消息为字符串
    std::string result(reinterpret_cast<char*>(out), out_final_len);
    delete[] out;

    // 释放解密上下文
    EVP_CIPHER_CTX_free(ctx);

    return result;
}

int main() {
    std::string message{"Hello, world!"};
    std::string key{"mysecretkey"};

    std::string ciphertext = encrypt(message, key);
    std::cout << "Encrypted message: " << ciphertext << '\n';

    std::string plaintext = decrypt(ciphertext, key);
    std::cout << "Decrypted message: " << plaintext << '\n';

    return 0;
}
```

以上代码使用了OpenSSL库中的EVP加密算法，通过EVP_EncryptInit_ex和EVP_DecryptInit_ex函数进行加解密上下文的初始化，然后使用EVP_EncryptUpdate和EVP_EncryptFinal_ex以及EVP_DecryptUpdate和EVP_DecryptFinal_ex函数进行加解密操作。需要注意的是，在实际使用中，key应该足够长以确保加密的安全性。

